#include <iostream>
#include <string>
#include <fstream>
#include <memory>

// --- RAII Class for File Handling ---
class FileHandler {
private:
    std::fstream file;
    std::string filename;
    bool isOpen;

public:
    // Acquire resource in constructor
    FileHandler(const std::string& name, std::ios::openmode mode) 
        : filename(name), isOpen(false) {
        file.open(name, mode);
        if (file.is_open()) {
            isOpen = true;
            std::cout << "📂 File '" << name << "' opened" << std::endl;
        } else {
            std::cout << "❌ Failed to open '" << name << "'" << std::endl;
        }
    }

    // Release resource in destructor
    ~FileHandler() {
        if (isOpen) {
            file.close();
            std::cout << "📁 File '" << filename << "' closed" << std::endl;
        }
    }

    // Prevent copying (RAII objects shouldn't be copied)
    FileHandler(const FileHandler&) = delete;
    FileHandler& operator=(const FileHandler&) = delete;

    // Allow moving
    FileHandler(FileHandler&& other) noexcept 
        : filename(std::move(other.filename)), isOpen(other.isOpen) {
        file = std::move(other.file);
        other.isOpen = false;
    }

    bool isOpen() const { return isOpen; }
    void write(const std::string& text) {
        if (isOpen) {
            file << text << std::endl;
        }
    }
};

// --- RAII Class for Game Resource ---
class GameResource {
private:
    std::string name;
    int* resource;

public:
    GameResource(const std::string& n, int size) : name(n) {
        resource = new int[size];
        for (int i = 0; i < size; i++) {
            resource[i] = i * 10;
        }
        std::cout << "🎮 Resource '" << name << "' acquired" << std::endl;
    }

    ~GameResource() {
        delete[] resource;
        std::cout << "🗑️ Resource '" << name << "' released" << std::endl;
    }

    GameResource(const GameResource&) = delete;
    GameResource& operator=(const GameResource&) = delete;

    GameResource(GameResource&& other) noexcept
        : name(std::move(other.name)), resource(other.resource) {
        other.resource = nullptr;
    }

    void use() const {
        std::cout << "🔧 Using '" << name << "' resource" << std::endl;
    }
};

// --- RAII Class for Mutex Lock ---
class MutexLock {
private:
    bool& locked;

public:
    MutexLock(bool& lock) : locked(lock) {
        if (locked) {
            std::cout << "⚠️ Mutex already locked!" << std::endl;
        } else {
            locked = true;
            std::cout << "🔒 Mutex locked" << std::endl;
        }
    }

    ~MutexLock() {
        if (locked) {
            locked = false;
            std::cout << "🔓 Mutex unlocked" << std::endl;
        }
    }
};

// Function that demonstrates exception safety with RAII
void riskyOperation() {
    FileHandler file("test.txt", std::ios::out);  // RAII: file will close even on exception

    file.write("This is a test");

    // Simulate exception
    // throw std::runtime_error("Something went wrong!");

    std::cout << "Function completed successfully" << std::endl;
} // file is automatically closed here (even on exception!)

int main() {
    std::cout << "=== RAII — Resource Acquisition Is Initialization ===" << std::endl;

    std::cout << "\n--- File Handler (RAII) ---" << std::endl;
    try {
        FileHandler file("example.txt", std::ios::out | std::ios::app);
        file.write("Hello, RAII!");
        file.write("This file will be closed automatically.");

        // file is automatically closed when going out of scope
    } // file destructor called automatically

    std::cout << "\n--- Game Resource (RAII) ---" << std::endl;
    {
        GameResource resource("PlayerData", 10);
        resource.use();
        // resource is destroyed at end of scope
    }

    std::cout << "\n--- Mutex Lock (RAII) ---" << std::endl;
    bool mutex = false;
    {
        MutexLock lock(mutex);  // Lock acquired
        // Critical section
        std::cout << "💻 Critical section executed" << std::endl;
    } // Lock released automatically

    std::cout << "\n--- Exception Safety ---" << std::endl;
    try {
        riskyOperation();
    } catch (const std::exception& e) {
        std::cout << "Exception caught: " << e.what() << std::endl;
    }

    std::cout << "\n--- RAII Benefits ---" << std::endl;
    std::cout << "✅ Automatic resource cleanup" << std::endl;
    std::cout << "✅ Exception-safe" << std::endl;
    std::cout << "✅ No memory leaks" << std::endl;
    std::cout << "✅ No forgotten cleanup" << std::endl;

    std::cout << "\n--- RAII in C++ ---" << std::endl;
    std::cout << "🔹 std::unique_ptr → RAII for heap memory" << std::endl;
    std::cout << "🔹 std::fstream → RAII for files" << std::endl;
    std::cout << "🔹 std::lock_guard → RAII for mutexes" << std::endl;

    return 0;
}

