#include <iostream>
#include <string>

class ResourceManager {
private:
    std::string name;
    bool hasResource;

public:
    ResourceManager(std::string n) : name(n), hasResource(true) {
        std::cout << "🔵 Acquired: '" << name << "'" << std::endl;
    }

    ~ResourceManager() {
        if (hasResource) {
            std::cout << "🔴 Released: '" << name << "'" << std::endl;
        }
    }

    ResourceManager(const ResourceManager&) = delete;
    ResourceManager& operator=(const ResourceManager&) = delete;

    ResourceManager(ResourceManager&& other) noexcept
        : name(std::move(other.name)), hasResource(other.hasResource) {
        other.hasResource = false;
        std::cout << "🔄 Transferred: '" << name << "'" << std::endl;
    }

    void use() const {
        if (hasResource) {
            std::cout << "⚡ Using: '" << name << "'" << std::endl;
        } else {
            std::cout << "❌ Resource is empty!" << std::endl;
        }
    }

    bool hasResource() const { return hasResource; }
};

int main() {
    std::cout << "=== RAII Demonstration ===" << std::endl;

    std::cout << "\n--- Block scope with RAII ---" << std::endl;
    {
        ResourceManager res("GameData");
        res.use();
    }  // res is automatically destroyed here

    std::cout << "\n--- Move with RAII ---" << std::endl;
    ResourceManager res2("PlayerData");
    res2.use();

    ResourceManager res3 = std::move(res2);
    res3.use();

    std::cout << "res2 has resource: " << (res2.hasResource() ? "Yes" : "No") << std::endl;

    return 0;
}
